module top_module(
    input clk,
    input rst,
    input en,
    output [3:0] count
);reg [3:0] cnt_reg;

    always @(posedge clk) begin
        if (rst) begin
            cnt_reg <= 4'b0;
        end else if (en) begin
            cnt_reg <= cnt_reg + 1;
        end
    end

    assign count = cnt_reg;

endmodule
